import{_ as a,o as n,c as t,a2 as o}from"./chunks/framework.DdLJaIXX.js";const u=JSON.parse('{"title":"CQ Agent Conventions — Unified Guide","description":"","frontmatter":{},"headers":[],"relativePath":"conventions/agent-conventions.md","filePath":"conventions/agent-conventions.md"}'),s={name:"conventions/agent-conventions.md"};function i(d,e,c,r,l,p){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="cq-agent-conventions-—-unified-guide" tabindex="-1">CQ Agent Conventions — Unified Guide <a class="header-anchor" href="#cq-agent-conventions-—-unified-guide" aria-label="Permalink to &quot;CQ Agent Conventions — Unified Guide&quot;">​</a></h1><blockquote><p>Single source of truth for every convention an agent must follow when talking to CQ. Each convention is also injected into the MCP <code>initialize</code> <code>Instructions</code> field so agents learn it before their first <code>tools/list</code> call — but this page is the canonical reference.</p></blockquote><h2 id="why-conventions-exist" tabindex="-1">Why conventions exist <a class="header-anchor" href="#why-conventions-exist" aria-label="Permalink to &quot;Why conventions exist&quot;">​</a></h2><p>CQ records relationships between conversations, experiments, and knowledge documents (the <strong>Timeline Graph</strong>, Phase 0) and surfaces them to researchers via verifiable URLs (<strong>Evidence Web</strong>, Phase 2). Both depend on the agent doing two small things consistently:</p><ol><li><strong>Declaring edges</strong> when it derives, extends, reproduces, contradicts, or compares prior work.</li><li><strong>Attaching URLs</strong> to its answers when it references a specific experiment, doc, or thread.</li></ol><p>Without these conventions, the graph stays empty and the Evidence Web has nothing to link to. <strong>CQ does not infer them.</strong> That&#39;s by design — explicit declarations carry the agent&#39;s intent; inferred edges would introduce noise and ambiguity.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>When you do this</th><th>Call this</th><th>Why</th></tr></thead><tbody><tr><td>Submit a derived experiment</td><td><code>cq_edge_declare</code> (<code>derives_from</code>)</td><td>Future sessions trace lineage</td></tr><tr><td>Reference an experiment in your answer</td><td><code>cq_evidence_url</code> (<code>type=exp</code>) + Markdown link</td><td>Researcher verifies in one click</td></tr><tr><td>Record a contradiction with prior work</td><td><code>cq_edge_declare</code> (<code>contradicts</code>)</td><td>Context Injection blacklists the bad doc</td></tr><tr><td>Compare N runs side-by-side</td><td><code>cq_evidence_url</code> (<code>type=compare</code>)</td><td>Single page shows overlay + diff</td></tr></tbody></table><hr><h1 id="convention-1-—-edge-declaration" tabindex="-1">Convention 1 — Edge Declaration <a class="header-anchor" href="#convention-1-—-edge-declaration" aria-label="Permalink to &quot;Convention 1 — Edge Declaration&quot;">​</a></h1><p>CQ records relationships in <code>cq_graph_edges</code>. Agents declare semantic edges via the <code>cq_edge_declare</code> MCP tool. The system will not infer them.</p><h2 id="when-to-call-cq-edge-declare" tabindex="-1">When to call <code>cq_edge_declare</code> <a class="header-anchor" href="#when-to-call-cq-edge-declare" aria-label="Permalink to &quot;When to call \`cq_edge_declare\`&quot;">​</a></h2><p>Call <strong>immediately after</strong> any of these actions:</p><ul><li>Submit an experiment varying one parameter from a prior one → <code>edge_type: derives_from</code></li><li>Submit an experiment that scales/extends a prior one → <code>edge_type: extends</code></li><li>Reproduce a published or prior result → <code>edge_type: reproduces</code></li><li>Record a finding that opposes a prior conclusion → <code>edge_type: contradicts</code></li><li>Compare experiments side-by-side in a knowledge doc → <code>edge_type: compared_to</code> (one call per baseline)</li></ul><h2 id="endpoint-types-only-these-4" tabindex="-1">Endpoint types (only these 4) <a class="header-anchor" href="#endpoint-types-only-these-4" aria-label="Permalink to &quot;Endpoint types (only these 4)&quot;">​</a></h2><ul><li><code>session</code> — <code>ai_sessions.session_id</code></li><li><code>job</code> — <code>hub_jobs.id</code></li><li><code>doc</code> — <code>c4_documents.doc_id</code> (e.g. <code>exp-abc12345</code>)</li><li><code>persona</code> — user UUID</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><p><code>derives_from</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cq_edge_declare(</span></span>
<span class="line"><span>  from_type=&quot;job&quot;,  from_id=&quot;&lt;new&gt;&quot;,</span></span>
<span class="line"><span>  to_type=&quot;job&quot;,    to_id=&quot;&lt;base&gt;&quot;,</span></span>
<span class="line"><span>  edge_type=&quot;derives_from&quot;,</span></span>
<span class="line"><span>  metadata={&quot;changed&quot;:[&quot;lr&quot;], &quot;from&quot;:&quot;1e-3&quot;, &quot;to&quot;:&quot;1e-4&quot;}</span></span>
<span class="line"><span>)</span></span></code></pre></div><p><code>compared_to</code> (one call per baseline):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cq_edge_declare(from_type=&quot;doc&quot;, from_id=&quot;doc-cmp-001&quot;,</span></span>
<span class="line"><span>                to_type=&quot;job&quot;,   to_id=&quot;job-a&quot;,</span></span>
<span class="line"><span>                edge_type=&quot;compared_to&quot;)</span></span></code></pre></div><p><code>contradicts</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cq_edge_declare(</span></span>
<span class="line"><span>  from_type=&quot;doc&quot;, from_id=&quot;doc-finding-002&quot;,</span></span>
<span class="line"><span>  to_type=&quot;doc&quot;,   to_id=&quot;doc-finding-001&quot;,</span></span>
<span class="line"><span>  edge_type=&quot;contradicts&quot;,</span></span>
<span class="line"><span>  metadata={&quot;reason&quot;:&quot;opposite val_loss trend&quot;}</span></span>
<span class="line"><span>)</span></span></code></pre></div><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><ol><li><strong>One call per relationship</strong> — do not batch.</li><li><code>metadata</code> is optional, ≤ 2 KB serialized; use it for the <em>reason</em>.</li><li><strong>Edges are immutable.</strong> Wrong edge → delete + re-declare (do not retry).</li><li><strong>Do not declare structural edges</strong> (<code>produced_in</code>, <code>authored_by</code>). Hooks own those — the tool returns <code>structural_edge_forbidden</code> if you try.</li><li>Edge declaration is best-effort. If it fails, continue your primary task.</li></ol><h2 id="failure-modes" tabindex="-1">Failure modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Error</th><th>Meaning</th></tr></thead><tbody><tr><td><code>structural_edge_forbidden</code></td><td>You tried to declare <code>produced_in</code> or <code>authored_by</code>.</td></tr><tr><td><code>invalid_edge_type</code></td><td>Unknown semantic edge; see <code>hint</code> for valid options.</td></tr><tr><td><code>invalid_from_type</code> / <code>invalid_to_type</code></td><td>Unknown endpoint kind.</td></tr><tr><td><code>missing_endpoint_id</code></td><td><code>from_id</code> or <code>to_id</code> was empty.</td></tr><tr><td><code>metadata_too_large</code></td><td>Serialized metadata &gt; 2 KB.</td></tr><tr><td><code>not_authenticated</code> / <code>session_expired</code></td><td>User must run <code>cq auth login</code>.</td></tr><tr><td><code>supabase_error</code></td><td>Server-side failure; inspect <code>hint</code>.</td></tr></tbody></table><hr><h1 id="convention-2-—-evidence-url-attachment" tabindex="-1">Convention 2 — Evidence URL Attachment <a class="header-anchor" href="#convention-2-—-evidence-url-attachment" aria-label="Permalink to &quot;Convention 2 — Evidence URL Attachment&quot;">​</a></h1><p>When your answer references a specific experiment, knowledge doc, or conversation thread, you <strong>must attach the canonical Evidence Web URL</strong> so the researcher can verify the evidence in one click.</p><h2 id="when-to-call-cq-evidence-url" tabindex="-1">When to call <code>cq_evidence_url</code> <a class="header-anchor" href="#when-to-call-cq-evidence-url" aria-label="Permalink to &quot;When to call \`cq_evidence_url\`&quot;">​</a></h2><p>Call it <strong>immediately before you finalize your answer</strong>, for each referenced resource:</p><ul><li>Mentioning an experiment by id (<code>exp-abc123</code>, <code>job-xyz</code>) → <code>type=&quot;exp&quot;</code></li><li>Referencing a knowledge doc → <code>type=&quot;doc&quot;</code></li><li>Pointing at a past conversation → <code>type=&quot;thread&quot;</code></li><li>Comparing multiple experiments → <code>type=&quot;compare&quot;</code> with <code>ids=[...]</code></li></ul><h2 id="returned-url-format" tabindex="-1">Returned URL format <a class="header-anchor" href="#returned-url-format" aria-label="Permalink to &quot;Returned URL format&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>exp     → {base}/exp/{id}</span></span>
<span class="line"><span>doc     → {base}/doc/{id}</span></span>
<span class="line"><span>thread  → {base}/thread/{id}</span></span>
<span class="line"><span>compare → {base}/compare?ids=a,b,c</span></span></code></pre></div><p>Attach them as Markdown links in your answer:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;The previous run [exp-abc123]({url}) used lr=1e-4 ...&quot;</span></span></code></pre></div><h2 id="rules-1" tabindex="-1">Rules <a class="header-anchor" href="#rules-1" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><ol><li><strong>One URL per mentioned resource.</strong> Don&#39;t batch references into a single link — each experiment/doc/thread gets its own mint.</li><li><code>compare</code> accepts 2-10 ids. If you need to compare &gt; 10, summarize first or split the comparison.</li><li>URL minting is offline-safe (pure construction). Errors return a structured <code>{error, message, hint}</code> — surface the hint, do not retry.</li><li>If the user is working without Evidence Web access (no browser, headless), still mint URLs — the researcher may paste them into their notes for later verification.</li><li><code>share=true</code> returns POST instructions for the user to mint a shareable token themselves (the MCP server doesn&#39;t carry the user&#39;s Supabase JWT, so the agent hands the user the recipe instead).</li></ol><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: &quot;어제 돌린 MNIST 실험이랑 오늘 꺼 비교해줘&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent (internal):</span></span>
<span class="line"><span>  [queries hub_jobs, finds exp-aaa (yesterday) and exp-bbb (today)]</span></span>
<span class="line"><span>  [cq_evidence_url(type=&quot;compare&quot;, ids=[&quot;aaa&quot;,&quot;bbb&quot;])</span></span>
<span class="line"><span>   → {url: &quot;https://cq.pilab.kr/compare?ids=aaa,bbb&quot;}]</span></span>
<span class="line"><span>  [cq_evidence_url(type=&quot;exp&quot;, id=&quot;aaa&quot;)  → exp URL]</span></span>
<span class="line"><span>  [cq_evidence_url(type=&quot;exp&quot;, id=&quot;bbb&quot;)  → exp URL]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Agent (output):</span></span>
<span class="line"><span>  &quot;[exp-aaa](https://cq.pilab.kr/exp/aaa) got val_loss 0.42,</span></span>
<span class="line"><span>   [exp-bbb](https://cq.pilab.kr/exp/bbb) got 0.31 — -26% improvement.</span></span>
<span class="line"><span>   [side-by-side](https://cq.pilab.kr/compare?ids=aaa,bbb)&quot;</span></span></code></pre></div><hr><h1 id="how-they-compose" tabindex="-1">How they compose <a class="header-anchor" href="#how-they-compose" aria-label="Permalink to &quot;How they compose&quot;">​</a></h1><p>Edge declaration and URL attachment work together — the agent both records the relationship in the graph <strong>and</strong> surfaces it to the user:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. cq_edge_declare(derives_from)  → Phase 0 graph</span></span>
<span class="line"><span>2. cq_evidence_url(exp)           → Phase 2 link</span></span>
<span class="line"><span>3. Answer with Markdown link      → Researcher verifies</span></span></code></pre></div><p>Future sessions reading this exchange will see both:</p><ul><li>The graph shows the lineage.</li><li>The evidence link shows the actual artifacts.</li></ul><hr><h1 id="forward-looking-phase-3" tabindex="-1">Forward-looking (Phase 3+) <a class="header-anchor" href="#forward-looking-phase-3" aria-label="Permalink to &quot;Forward-looking (Phase 3+)&quot;">​</a></h1><p>The conventions list is intentionally short. Planned additions:</p><ul><li><strong>Reproduction reporting</strong> — when an agent re-runs <code>reproduces</code> and the result diverges, declare a follow-up <code>contradicts</code> edge.</li><li><strong>Decision logging</strong> — durable record of &quot;why we chose X over Y&quot; with trade-off metadata.</li><li><strong>Confidence calibration</strong> — agent self-reports confidence on inferences; future sessions weight by that signal.</li></ul><p>These are speculative; current code only enforces the two above.</p><hr><h1 id="appendix-a-—-one-line-summary-marketing" tabindex="-1">Appendix A — One-line summary (marketing) <a class="header-anchor" href="#appendix-a-—-one-line-summary-marketing" aria-label="Permalink to &quot;Appendix A — One-line summary (marketing)&quot;">​</a></h1><blockquote><p>CQ agents declare every research relationship in a queryable graph and attach a verification URL to every claim — so future sessions know <em>why</em> the decision was made and the researcher can check <em>that</em> it was right in one click.</p></blockquote><h1 id="appendix-b-—-cheat-sheet" tabindex="-1">Appendix B — Cheat-sheet <a class="header-anchor" href="#appendix-b-—-cheat-sheet" aria-label="Permalink to &quot;Appendix B — Cheat-sheet&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You did this                         → Call this</span></span>
<span class="line"><span>─────────────────────────────────────  ─────────────────────────────</span></span>
<span class="line"><span>Submitted a tweaked variant         → cq_edge_declare(derives_from)</span></span>
<span class="line"><span>Scaled it up                        → cq_edge_declare(extends)</span></span>
<span class="line"><span>Reran a paper&#39;s claim               → cq_edge_declare(reproduces)</span></span>
<span class="line"><span>Found an opposing result            → cq_edge_declare(contradicts)</span></span>
<span class="line"><span>Compared 2-10 runs in a doc         → cq_edge_declare(compared_to) × N</span></span>
<span class="line"><span>Mentioned exp-X in your answer      → cq_evidence_url(exp, X) + link</span></span>
<span class="line"><span>Mentioned doc-Y in your answer      → cq_evidence_url(doc, Y) + link</span></span>
<span class="line"><span>Mentioned a past thread             → cq_evidence_url(thread, Z) + link</span></span>
<span class="line"><span>Showed N runs in your answer        → cq_evidence_url(compare, ids=…)</span></span></code></pre></div><h1 id="appendix-c-—-file-layout" tabindex="-1">Appendix C — File layout <a class="header-anchor" href="#appendix-c-—-file-layout" aria-label="Permalink to &quot;Appendix C — File layout&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs/conventions/agent-conventions.md          ← THIS FILE (SSOT)</span></span>
<span class="line"><span>docs/conventions/agent-edge-declaration.md     ← legacy, content here</span></span>
<span class="line"><span>c4-core/cmd/c4/agent_edge_convention.go        ← inline build copy</span></span>
<span class="line"><span>c4-core/cmd/c4/agent_evidence_convention.go    ← inline build copy</span></span></code></pre></div><p>The two <code>agent_*_convention.go</code> files contain compact build-embedded versions injected into the MCP <code>initialize</code> response. Both reference this guide as their full reference. Edits here should be reflected in the inline copies for consistency (a smoke test in <code>agent_*_convention_test.go</code> guards the structural invariants).</p>`,60)])])}const g=a(s,[["render",i]]);export{u as __pageData,g as default};
